-- Import 1888 prodotti dal catalogo Mikai completo + 261 strumenti.
-- Sorgente: codici_descrizioni_completo_con_strumenti.xlsx
-- Famiglia ricavata da pattern sulle descrizioni (vedi script /tmp/build_migration.js).
-- Brand: Mikai. Tipo: pezzo_sfuso per impianti/viti/fili, strumentario per strumenti.

-- 1. Famiglia retroattiva per prodotti seed esistenti
UPDATE products SET famiglia = 'Stylo - Fissatore' WHERE codice = 'STYLO' AND famiglia IS NULL;
UPDATE products SET famiglia = 'FEP - Fissatore' WHERE codice = 'FEP' AND famiglia IS NULL;
UPDATE products SET famiglia = 'VCA - Viti piede piatto' WHERE codice = 'VCA' AND famiglia IS NULL;
UPDATE products SET famiglia = 'Viti compressione headless' WHERE codice = 'BSS' AND famiglia IS NULL;
UPDATE products SET famiglia = 'MiniStylo - Fissatore' WHERE codice = 'MINISTYLO' AND famiglia IS NULL;
UPDATE products SET famiglia = 'Medartis - Placche' WHERE codice = 'MED-PLAC' AND famiglia IS NULL;
UPDATE products SET famiglia = 'Medartis - Viti' WHERE codice = 'MED-VITI' AND famiglia IS NULL;
UPDATE products SET famiglia = 'Sawbones - Ossa sintetiche' WHERE brand_id = 'b0000003-0000-0000-0000-000000000003' AND famiglia IS NULL;

-- 2. Bulk insert (chunks da 200 righe)
-- Chunk 1 (1..200)
ON CONFLICT (codice) DO UPDATE SET
  descrizione = EXCLUDED.descrizione,
  famiglia    = COALESCE(products.famiglia, EXCLUDED.famiglia),
  updated_at  = now();

